using Microsoft.AspNetCore.HttpOverrides;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddScoped<IUserService, UserService>();

// [.NET 9 fix] Changed from AddSingleton to AddScoped.
// ValidateScopes is now enabled by default in development; a singleton
// capturing a scoped IUserService would throw InvalidOperationException
// ("Cannot resolve scoped service from root provider") at startup.
builder.Services.AddScoped<ICacheService>(sp =>
    new CacheService(sp.GetRequiredService<IUserService>()));

// [.NET 9 fix] HttpClientFactory now uses SocketsHttpHandler by default.
// The previous cast to HttpClientHandler would throw InvalidCastException.
// Use ConfigurePrimaryHttpMessageHandler to set the handler type explicitly.
builder.Services.AddHttpClient("api")
    .ConfigurePrimaryHttpMessageHandler(() => new HttpClientHandler { UseCookies = false });

// [.NET 9 fix] Header values in Trace-level HttpClientFactory logs are now
// redacted by default. Allowlist the specific non-sensitive headers you need
// to see when debugging request headers.
builder.Services.ConfigureHttpClientDefaults(b =>
    b.RedactLoggedHeaders(h =>
        h != "Accept" &&
        h != "Content-Type" &&
        h != "Cache-Control" &&
        h != "X-Request-Id"));

// [.NET 9 fix] ForwardedHeadersMiddleware now ignores X-Forwarded-* headers
// from proxies not listed in KnownProxies or KnownNetworks. Configure your
// reverse proxy address here; the loopback entry below is a placeholder.
builder.Services.Configure<ForwardedHeadersOptions>(options =>
{
    options.ForwardedHeaders = ForwardedHeaders.XForwardedFor;
    options.KnownProxies.Add(System.Net.IPAddress.Loopback);
});
var app = builder.Build();
app.UseForwardedHeaders();
app.Run();

